member.example:
The following example shows a OneClick control used on a page.

<%@ Register tagprefix="mboc" namespace="MetaBuilders.WebControls" assembly="MetaBuilders.WebControls.OneClick" %>
<script runat="server" language="c#" >
 protected void Button1_Click( Object sender, EventArgs e ) {
	if ( OneClick1.IsValid ) {
		// Code here is important to happen only once, and might take substantial amounts of time to complete
		// For example purposes, the thread will be put to sleep for 3 seconds.
		System.Threading.Thread.Sleep( TimeSpan.FromSeconds(3) );
	}
}
</script>
<html><body><form runat="server" >
	<mboc:OneClick runat="server" Id="OneClick1" />
	<asp:Button runat="server" OnClick="Button1_Click" Text="Do Something Important" />
</form></body></html>
